import { signOut } from 'firebase/auth';
import { useEffect, useState } from 'react';
import { Image, StyleSheet, Text, TouchableOpacity, View, Animated } from 'react-native';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { auth } from '../lib/firebase';

const ProfileScreen = ({ navigation }) => {
  const { isDark } = useTheme();
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [fadeAnim] = useState(new Animated.Value(0)); // fade animation

  useEffect(() => {
    if (!user) {
      navigation.replace('SignIn');
    } else {
      setLoading(false);
      // run animation
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 600,
        useNativeDriver: true,
      }).start();
    }
  }, [user, navigation]);

  const handleSignOut = async () => {
    try {
      await signOut(auth);
      navigation.replace('SignIn');
    } catch (error) {
      console.error('Error signing out:', error);
    }
  };

  if (loading) {
    return (
      <View style={[styles.container, { backgroundColor: isDark ? '#111827' : '#fff7ed' }]}>
        <Text style={[styles.name, { color: isDark ? '#fff' : '#000' }]}>Loading...</Text>
      </View>
    );
  }

  return (
    <View style={[styles.container, { backgroundColor: isDark ? '#111827' : '#fff7ed' }]}>
      <Animated.View style={[styles.content, { opacity: fadeAnim }]}>
        <View style={styles.header}>
          <Image
            source={{uri: "data:image/jpeg;base64,"}}
            style={styles.profileImage}
          />
          <Text style={[styles.name, { color: isDark ? '#fff' : '#000' }]}>
            {user?.displayName || 'User'}
          </Text>
          <Text style={[styles.email, { color: isDark ? '#9ca3af' : '#6b7280' }]}>
            {user?.email || ''}
          </Text>
        </View>

        <View style={styles.section}>
          <TouchableOpacity
            style={[styles.menuItem, { backgroundColor: isDark ? '#1f2937' : '#fff' }]}
            onPress={() => navigation.navigate('EditProfile')}
          >
            <Text style={[styles.menuText, { color: isDark ? '#fff' : '#000' }]}>Edit Profile</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.menuItem, { backgroundColor: isDark ? '#1f2937' : '#fff' }]}
            onPress={() => navigation.navigate('OrdersTab')}
          >
            <Text style={[styles.menuText, { color: isDark ? '#fff' : '#000' }]}>My Orders</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.menuItem, { backgroundColor: isDark ? '#1f2937' : '#fff' }]}
            onPress={() => navigation.navigate('Settings')}
          >
            <Text style={[styles.menuText, { color: isDark ? '#fff' : '#000' }]}>Settings</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.signOutButton]}
            onPress={handleSignOut}
          >
            <Text style={styles.signOutText}>Sign Out</Text>
          </TouchableOpacity>
        </View>
      </Animated.View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center', // center everything vertically
    alignItems: 'center', // center horizontally
  },
  content: {
    width: '85%',
    alignItems: 'center',
  },
  header: {
    alignItems: 'center',
    marginBottom: 20,
  },
  profileImage: {
    width: 100,
    height: 100,
    borderRadius: 50,
    marginBottom: 10,
  },
  name: {
    fontSize: 24,
    fontWeight: 'bold',
    marginBottom: 5,
  },
  email: {
    fontSize: 16,
  },
  section: {
    width: '100%',
  },
  menuItem: {
    padding: 15,
    borderRadius: 8,
    marginBottom: 10,
  },
  menuText: {
    fontSize: 16,
    textAlign: 'center',
  },
  signOutButton: {
    backgroundColor: '#ef4444',
    padding: 15,
    borderRadius: 8,
    marginTop: 20,
  },
  signOutText: {
    color: '#fff',
    textAlign: 'center',
    fontSize: 16,
    fontWeight: 'bold',
  },
});

export default ProfileScreen;
